const rows = $input.all().map(i => i.json);
const istOffset = 5.5 * 60 * 60 * 1000;
const now = new Date();
const msDay = 24*60*60*1000;
const istStr = d => new Date(d.getTime()+istOffset).toISOString().split('T')[0];

const cutCurrent = now.getTime() - 7*msDay;
const cutPrior   = now.getTime() - 28*msDay;

let current = [], prior = [];
for (const r of rows){
  if(!r.timestamp) continue;
  const t = new Date(r.timestamp);
  if(isNaN(t.getTime())) continue;
  const ms = t.getTime();
  const amt = parseFloat(r.amount)||0;
  if(ms >= cutCurrent) current.push({...r, amt});
  else if(ms >= cutPrior) prior.push({...r, amt});
}

const week_start = istStr(new Date(now.getTime() - 6*msDay));
const week_end   = istStr(now);

if(current.length === 0){
  return [{ json: {
    hasData: false, week_start, week_end,
    noDataText: `📈 Weekly Insight — ${week_start} to ${week_end}\n\nNo expenses logged this week. 🌱`
  }}];
}

const sum = a => a.reduce((s,r)=>s+r.amt,0);
const currentTotal = sum(current);
const priorWeeklyAvg = Math.round(sum(prior)/3);

const catTotals = arr => { const m={}; for(const r of arr){const c=r.category||'Uncategorized'; m[c]=(m[c]||0)+r.amt;} return m; };
const curCat = catTotals(current), priCat = catTotals(prior);

const category_breakdown = Object.entries(curCat).sort((a,b)=>b[1]-a[1])
  .map(([category,amount])=>({ category, amount: Math.round(amount), prior_avg: Math.round((priCat[category]||0)/3) }));

const needTotal = current.filter(r=>(r.need_or_want||'').toLowerCase()==='need').reduce((s,r)=>s+r.amt,0);
const need_pct = currentTotal>0 ? Math.round(needTotal/currentTotal*100) : 0;

let big = current.reduce((mx,r)=> r.amt>((mx&&mx.amt)||0)?r:mx, null);
const biggest_transaction = big ? { merchant: big.merchant_vendor||'Unknown', amount: Math.round(big.amt), category: big.category||'Other' } : null;

const anomalies = [];
for(const c of category_breakdown){
  if(c.prior_avg > 0 && c.amount >= c.prior_avg*1.5 && (c.amount-c.prior_avg) >= 300){
    const pct = Math.round((c.amount-c.prior_avg)/c.prior_avg*100);
    anomalies.push(`${c.category} up ${pct}% vs 3-week avg (₹${c.amount} vs ₹${c.prior_avg})`);
  } else if(c.prior_avg === 0 && c.amount >= 500){
    anomalies.push(`${c.category} is new this week (₹${c.amount})`);
  }
}
const anomaly_flag = anomalies.length>0;
const anomaly_detail = anomalies.join('; ') || 'None';

const stats = {
  week_start, week_end,
  current_week_total: Math.round(currentTotal),
  prior_3wk_avg_total: priorWeeklyAvg,
  transaction_count: current.length,
  need_pct, want_pct: 100-need_pct,
  category_breakdown, biggest_transaction,
  anomaly_flag, anomaly_detail
};
return [{ json: { hasData: true, ...stats, statsJson: JSON.stringify(stats) } }];

const raw = $input.first().json;
let narrative = (raw.candidates?.[0]?.content?.parts?.[0]?.text || '').trim();
const agg = $('Aggregate Week').first().json;
if(!narrative){
  narrative = `📈 Weekly Insight — ${agg.week_start} to ${agg.week_end}\n\nTotal: ₹${agg.current_week_total} (3-wk avg ₹${agg.prior_3wk_avg_total})`;
}
return [{ json: {
  week_start: agg.week_start,
  insight_text: narrative,
  anomaly_flag: agg.anomaly_flag,
  anomaly_detail: agg.anomaly_detail
}}];
